import React from 'react';
import { Card, Stack, Heading, Text, Divider, Box, Icon } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{
    day?: string;
    icon?: string;
    high?: number;
    low?: number;
  }>;
}

export default function WeatherCard(props: Props): React.ReactElement {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  return (
    <Card shadow="md" radius="lg" padding={24}>
      <Stack gap={16} direction="vertical">
        {/* City Name */}
        <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
          {city}
        </Heading>

        {/* Temperature and Metrics Row */}
        <Stack gap={24} direction="horizontal" align="center">
          {/* Left: Temperature + Condition */}
          <Stack gap={8} direction="vertical" align="center">
            <div
              style={{
                fontSize: '60px',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-600, #0284c7)',
                lineHeight: '1',
              }}
            >
              {temperature}°
            </div>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
              {condition}
            </Text>
          </Stack>

          {/* Right: Humidity and Wind Speed */}
          <Stack gap={12} direction="vertical">
            {/* Humidity */}
            <Stack gap={4} direction="vertical">
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>

            {/* Wind Speed */}
            <Stack gap={4} direction="vertical">
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind Speed
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>
        </Stack>

        {/* Divider */}
        <Divider margin={12} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast */}
        <Stack
          gap={12}
          direction="horizontal"
          wrap={true}
          justify="between"
          align="stretch"
        >
          {forecast.map((item, index) => (
            <Box
              key={index}
              padding={12}
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{
                flex: '0 0 auto',
                minWidth: '80px',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              {/* Day Name */}
              <Text
                variant="label"
                align="center"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {item.day ?? 'Day'}
              </Text>

              {/* Weather Icon/Emoji */}
              <div style={{ fontSize: '24px', lineHeight: '1' }}>
                {item.icon ?? '☀️'}
              </div>

              {/* High/Low Temps */}
              <Text
                variant="caption"
                align="center"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {item.high ?? 0}° / {item.low ?? 0}°{unit}
              </Text>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Alert,
  Badge,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface Errors {
  name: string;
  email: string;
  satisfaction: string;
}

export default function SurveyForm(props: Props) {
  const [currentStep, setCurrentStep] = useState<number>(1);
  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });
  const [errors, setErrors] = useState<Errors>({
    name: '',
    email: '',
    satisfaction: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'success' | 'error' | null>(null);
  const [submitMessage, setSubmitMessage] = useState('');

  const validateEmail = (email: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const validateStep = (step: number): boolean => {
    const newErrors: Errors = { name: '', email: '', satisfaction: '' };
    let isValid = true;

    if (step === 1) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
        isValid = false;
      }
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
        isValid = false;
      } else if (!validateEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email';
        isValid = false;
      }
    } else if (step === 2) {
      if (!formData.satisfaction) {
        newErrors.satisfaction = 'Please select a rating';
        isValid = false;
      }
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleNext = () => {
    if (validateStep(currentStep)) {
      if (currentStep < 5) {
        setCurrentStep(currentStep + 1);
      }
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    setIsSubmitting(true);
    setSubmitStatus(null);

    try {
      const payload = {
        name: formData.name,
        email: formData.email,
        satisfaction: parseInt(formData.satisfaction),
        features: formData.features,
        comments: formData.comments,
      };

      if (props.onSubmit) {
        props.onSubmit(payload);
      }

      setSubmitStatus('success');
      setSubmitMessage('Survey submitted successfully!');
      setTimeout(() => {
        setCurrentStep(1);
        setFormData({
          name: '',
          email: '',
          satisfaction: '',
          features: [],
          comments: '',
        });
        setSubmitStatus(null);
      }, 2000);
    } catch (error) {
      setSubmitStatus('error');
      setSubmitMessage('Failed to submit survey. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleFeatureToggle = (feature: string) => {
    setFormData((prev) => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter((f) => f !== feature)
        : [...prev.features, feature],
    }));
  };

  const renderStep = () => {
    switch (currentStep) {
      case 1:
        return (
          <Stack direction="vertical" gap={16}>
            <Heading level={3}>Contact Information</Heading>
            <Input
              label="Name"
              placeholder="Enter your name"
              value={formData.name}
              onChange={(value) => setFormData({ ...formData, name: value })}
              required
              error={errors.name}
            />
            <Input
              label="Email"
              type="email"
              placeholder="Enter your email"
              value={formData.email}
              onChange={(value) => setFormData({ ...formData, email: value })}
              required
              error={errors.email}
            />
          </Stack>
        );

      case 2:
        return (
          <Stack direction="vertical" gap={16}>
            <Heading level={3}>How satisfied are you?</Heading>
            <RadioGroup
              label="Satisfaction Rating"
              value={formData.satisfaction}
              onChange={(value) => setFormData({ ...formData, satisfaction: value })}
              options={props.satisfactionLabels.map((label, index) => ({
                value: index.toString(),
                label,
              }))}
              direction="vertical"
              error={errors.satisfaction}
            />
          </Stack>
        );

      case 3:
        return (
          <Stack direction="vertical" gap={16}>
            <Heading level={3}>Which features interest you?</Heading>
            <Stack direction="vertical" gap={12}>
              {props.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={formData.features.includes(feature)}
                  onChange={() => handleFeatureToggle(feature)}
                />
              ))}
            </Stack>
          </Stack>
        );

      case 4:
        return (
          <Stack direction="vertical" gap={16}>
            <Heading level={3}>Additional Comments</Heading>
            <TextArea
              label="Comments"
              placeholder="Share any additional feedback or comments (optional)"
              value={formData.comments}
              onChange={(value) => setFormData({ ...formData, comments: value })}
              rows={6}
              maxLength={500}
              showCount
            />
          </Stack>
        );

      case 5:
        return (
          <Card shadow="md" padding={24} radius="lg">
            <Stack direction="vertical" gap={20}>
              <Heading level={3}>Review Your Answers</Heading>

              <Stack direction="vertical" gap={8}>
                <Heading level={5}>Contact Information</Heading>
                <Text variant="body">
                  <strong>Name:</strong> {formData.name}
                </Text>
                <Text variant="body">
                  <strong>Email:</strong> {formData.email}
                </Text>
              </Stack>

              <Stack direction="vertical" gap={8}>
                <Heading level={5}>Satisfaction Rating</Heading>
                <Text variant="body">
                  {props.satisfactionLabels[parseInt(formData.satisfaction)] ??
                    'Not selected'}
                </Text>
              </Stack>

              <Stack direction="vertical" gap={8}>
                <Heading level={5}>Interested Features</Heading>
                {formData.features.length > 0 ? (
                  <Stack direction="horizontal" gap={8} wrap>
                    {formData.features.map((feature) => (
                      <Badge key={feature} variant="primary" size="sm">
                        {feature}
                      </Badge>
                    ))}
                  </Stack>
                ) : (
                  <Text variant="body">No features selected</Text>
                )}
              </Stack>

              <Stack direction="vertical" gap={8}>
                <Heading level={5}>Comments</Heading>
                <Text variant="body">
                  {formData.comments.length > 100
                    ? formData.comments.slice(0, 100) + '...'
                    : formData.comments || '(No comments)'}
                </Text>
              </Stack>
            </Stack>
          </Card>
        );

      default:
        return null;
    }
  };

  return (
    <Container maxWidth="lg" padding={24} center>
      <Stack direction="vertical" gap={20}>
        <Stack direction="vertical" gap={8}>
          <Text variant="label">Step {currentStep} of 5</Text>
          <Progress value={currentStep} max={5} showLabel={false} />
        </Stack>

        <Stack direction="vertical" gap={24}>
          {renderStep()}
        </Stack>

        {submitStatus === 'success' && (
          <Alert
            variant="success"
            title="Survey Submitted"
            closable
            onClose={() => setSubmitStatus(null)}
          >
            {submitMessage}
          </Alert>
        )}

        {submitStatus === 'error' && (
          <Alert
            variant="error"
            title="Submission Failed"
            closable
            onClose={() => setSubmitStatus(null)}
          >
            {submitMessage}
          </Alert>
        )}

        <Stack
          direction="horizontal"
          gap={12}
          justify="between"
          align="center"
        >
          <Button
            variant="ghost"
            size="md"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>

          <Button
            variant="primary"
            size="md"
            onClick={currentStep === 5 ? handleSubmit : handleNext}
            disabled={isSubmitting}
            loading={isSubmitting}
          >
            {currentStep === 5 ? 'Submit' : 'Next'}
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Container,
  Stack,
  Input,
  Button,
  Box,
  Card,
  Text,
  Heading,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, { bg: string; text: string }> = {
  'alkali-metal': {
    bg: 'var(--ggui-color-primary-100, #e0f2fe)',
    text: 'var(--ggui-color-primary-700, #0369a1)',
  },
  'alkaline-earth': {
    bg: 'var(--ggui-color-primary-50, #f0f9ff)',
    text: 'var(--ggui-color-primary-800, #075985)',
  },
  'transition-metal': {
    bg: 'var(--ggui-color-warning-100, #fef3c7)',
    text: 'var(--ggui-color-warning-700, #b45309)',
  },
  'post-transition': {
    bg: 'var(--ggui-color-info-100, #cffafe)',
    text: 'var(--ggui-color-info-700, #0e7490)',
  },
  metalloid: {
    bg: 'var(--ggui-color-warning-50, #fffbeb)',
    text: 'var(--ggui-color-warning-800, #78350f)',
  },
  nonmetal: {
    bg: 'var(--ggui-color-success-100, #dcfce7)',
    text: 'var(--ggui-color-success-700, #15803d)',
  },
  halogen: {
    bg: 'var(--ggui-color-error-100, #fee2e2)',
    text: 'var(--ggui-color-error-700, #b91c1c)',
  },
  'noble-gas': {
    bg: 'var(--ggui-color-primary-100, #e0f2fe)',
    text: 'var(--ggui-color-primary-600, #0284c7)',
  },
};

export default function PeriodicTable(props: Props) {
  const { elements } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    return elements.filter((el) => {
      const query = searchQuery.toLowerCase();
      return (
        (el.name?.toLowerCase().includes(query) ?? false) ||
        (el.symbol?.toLowerCase().includes(query) ?? false)
      );
    });
  }, [elements, searchQuery]);

  const categoryMap = useMemo(() => {
    const map = new Map<string, Element[]>();
    elements.forEach((el) => {
      const cat = el.category ?? 'unknown';
      if (!map.has(cat)) map.set(cat, []);
      map.get(cat)!.push(el);
    });
    return map;
  }, [elements]);

  const getCategoryColors = (category?: string) => {
    if (!category) {
      return {
        bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
      };
    }
    return (
      categoryColorMap[category.toLowerCase()] ?? {
        bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
      }
    );
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        {/* Page Title */}
        <Heading level={1} align="center">
          Periodic Table of Elements
        </Heading>

        {/* Search Bar */}
        <Stack direction="horizontal" gap={16} align="center">
          <div style={{ flex: 1 }}>
            <Input
              label="Search elements"
              placeholder="Search by element name or symbol..."
              value={searchQuery}
              onChange={setSearchQuery}
            />
          </div>
          {searchQuery && (
            <Button variant="secondary" size="md" onClick={() => setSearchQuery('')}>
              Clear
            </Button>
          )}
        </Stack>

        <Divider />

        {/* Grid Container */}
        <Box
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius={12}
          padding={16}
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2, 8px)',
            minHeight: '600px',
          }}
        >
          {filteredElements.map((el) => {
            const colors = getCategoryColors(el.category);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            return (
              <Card
                key={`${el.atomicNumber}-${el.symbol}`}
                padding={8}
                radius="md"
                border={true}
                shadow="sm"
                onClick={() => setSelectedElement(el)}
                style={{
                  gridRow: el.row ?? 'auto',
                  gridColumn: el.col ?? 'auto',
                  backgroundColor: colors.bg,
                  cursor: 'pointer',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'space-between',
                  minHeight: '80px',
                  borderColor: isSelected
                    ? 'var(--ggui-color-primary-600, #0284c7)'
                    : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                  borderWidth: isSelected ? '2px' : '1px',
                  transition: 'all 200ms ease-in-out',
                  transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                }}
                onMouseEnter={(e) => {
                  (e.currentTarget as HTMLElement).style.boxShadow =
                    'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                  (e.currentTarget as HTMLElement).style.transform = 'scale(1.02)';
                }}
                onMouseLeave={(e) => {
                  (e.currentTarget as HTMLElement).style.boxShadow =
                    'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))';
                  (e.currentTarget as HTMLElement).style.transform = isSelected
                    ? 'scale(1.05)'
                    : 'scale(1)';
                }}
              >
                {/* Atomic Number - Top Left */}
                <Text
                  variant="caption"
                  size="xs"
                  color={colors.text}
                  align="left"
                  weight="normal"
                >
                  {el.atomicNumber ?? '?'}
                </Text>

                {/* Symbol - Center */}
                <Text
                  variant="body"
                  size="lg"
                  weight="bold"
                  color={colors.text}
                  align="center"
                >
                  {el.symbol ?? '?'}
                </Text>

                {/* Atomic Weight - Bottom Right */}
                {el.atomicWeight && (
                  <Text
                    variant="caption"
                    size="xs"
                    color={colors.text}
                    align="right"
                    weight="normal"
                  >
                    {el.atomicWeight.toFixed(3)}
                  </Text>
                )}
              </Card>
            );
          })}
        </Box>

        <Divider />

        {/* Legend */}
        <Stack gap={16}>
          <Heading level={3}>Element Categories</Heading>
          <Stack
            direction="horizontal"
            gap={16}
            wrap={true}
            align="start"
          >
            {Array.from(categoryMap.entries()).map(([category, items]) => {
              const colors = getCategoryColors(category);
              return (
                <Stack
                  key={category}
                  direction="horizontal"
                  gap={8}
                  align="center"
                >
                  <div
                    style={{
                      width: '20px',
                      height: '20px',
                      backgroundColor: colors.bg,
                      border: `1px solid ${colors.text}`,
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    }}
                  />
                  <Text variant="label" color={colors.text}>
                    {category}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    ({items.length})
                  </Text>
                </Stack>
              );
            })}
          </Stack>
        </Stack>

        {/* Detail Panel */}
        {selectedElement && (
          <>
            <Divider />
            <Box
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              padding={24}
              borderRadius={12}
              style={{
                borderTop: '2px solid var(--ggui-color-primary-600, #0284c7)',
              }}
            >
              <Stack gap={16}>
                <Stack direction="horizontal" gap={16} align="center" justify="between">
                  <Stack gap={8} align="start">
                    <Heading level={2}>{selectedElement.symbol}</Heading>
                    <Text variant="bodyLarge">{selectedElement.name}</Text>
                  </Stack>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setSelectedElement(null)}
                  >
                    ✕
                  </Button>
                </Stack>

                <Divider />

                <Stack gap={12}>
                  <Stack direction="horizontal" gap={24}>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Atomic Number
                      </Text>
                      <Text variant="body" weight="semibold">
                        {selectedElement.atomicNumber ?? 'N/A'}
                      </Text>
                    </Stack>

                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Atomic Weight
                      </Text>
                      <Text variant="body" weight="semibold">
                        {selectedElement.atomicWeight?.toFixed(3) ?? 'N/A'}
                      </Text>
                    </Stack>

                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Category
                      </Text>
                      <Badge variant="primary" size="md">
                        {selectedElement.category ?? 'Unknown'}
                      </Badge>
                    </Stack>
                  </Stack>

                  {selectedElement.row && selectedElement.col && (
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Position (Row × Col)
                      </Text>
                      <Text variant="body">
                        {selectedElement.row} × {selectedElement.col}
                      </Text>
                    </Stack>
                  )}
                </Stack>
              </Stack>
            </Box>
          </>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Stack,
  Card,
  Box,
  Heading,
  Text,
  Button,
  Badge,
  Tabs,
  Table,
  Icon,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  product?: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: Array<{ key?: string; value?: string }>;
    reviews?: Array<{
      author?: string;
      rating?: number;
      text?: string;
      date?: string;
    }>;
  };
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent(props: Props) {
  const product = props.product ?? {};
  const [quantity, setQuantity] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [submitSuccess, setSubmitSuccess] = useState(false);
  const [activeTab, setActiveTab] = useState('description');

  const productId = product.id ?? 'unknown';
  const productName = product.name ?? 'Product';
  const price = product.price ?? 0;
  const currency = product.currency ?? 'USD';
  const rating = product.rating ?? 0;
  const reviewCount = product.reviewCount ?? 0;
  const stock = product.stock ?? 0;
  const description = product.description ?? 'No description available';
  const specifications = product.specifications ?? [];
  const reviews = product.reviews ?? [];

  const handleIncrement = () => {
    if (quantity < stock) {
      setQuantity(quantity + 1);
    }
  };

  const handleDecrement = () => {
    if (quantity > 1) {
      setQuantity(quantity - 1);
    }
  };

  const handleAddToCart = async () => {
    setIsSubmitting(true);
    setSubmitError(null);
    try {
      await props.onAddToCart?.({
        productId,
        quantity,
      });
      setSubmitSuccess(true);
      setTimeout(() => setSubmitSuccess(false), 2000);
    } catch (error) {
      setSubmitError(error instanceof Error ? error.message : 'Error adding to cart');
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderStars = (rating: number) => {
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      if (i <= Math.floor(rating)) {
        stars.push(<span key={i}>★</span>);
      } else if (i - rating < 1 && i - rating > 0) {
        stars.push(<span key={i}>☆</span>);
      } else {
        stars.push(<span key={i}>☆</span>);
      }
    }
    return stars;
  };

  const isLowStock = stock > 0 && stock <= 3;
  const isOutOfStock = stock === 0;

  const specColumns = [
    { key: 'key', header: 'Property' },
    { key: 'value', header: 'Value' },
  ];

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Stack gap={16} direction="vertical">
          <Text variant="body">{description}</Text>
        </Stack>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content:
        specifications.length > 0 ? (
          <Table
            columns={specColumns}
            data={specifications.map((spec) => ({
              key: spec.key ?? '',
              value: spec.value ?? '',
            }))}
            striped={true}
          />
        ) : (
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            No specifications available
          </Text>
        ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content:
        reviews.length > 0 ? (
          <Stack gap={16} direction="vertical">
            {reviews.map((review, idx) => (
              <Card key={idx} padding={16} shadow="sm">
                <Stack gap={8} direction="vertical">
                  <Stack gap={8} direction="horizontal" justify="between" align="start">
                    <Text variant="label">{review.author ?? 'Anonymous'}</Text>
                    <div style={{ display: 'flex', gap: 'var(--ggui-spacing-1, 4px)', fontSize: '14px' }}>
                      {renderStars(review.rating ?? 0)}
                    </div>
                  </Stack>
                  <Text variant="body">{review.text ?? 'No text'}</Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {review.date ?? 'No date'}
                  </Text>
                </Stack>
              </Card>
            ))}
          </Stack>
        ) : (
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            No reviews yet
          </Text>
        ),
    },
  ];

  return (
    <Container maxWidth="2xl" padding={24} center={true}>
      <Stack gap={32} direction="vertical">
        {/* Top Section: Product Showcase */}
        <Stack
          gap={32}
          direction="horizontal"
          align="start"
          style={{
            flexDirection: 'column',
          }}
          wrap={true}
        >
          {/* Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-50, #f0f9ff)"
            padding={32}
            borderRadius={12}
            style={{
              flex: '0 0 100%',
              minHeight: '300px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              '@media (min-width: 768px)': {
                flex: '0 0 45%',
              },
            }}
          >
            <Stack gap={12} direction="vertical" align="center" justify="center">
              <Icon name="package" size={48} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="label" align="center">
                {productName}
              </Text>
            </Stack>
          </Box>

          {/* Details Section */}
          <Stack
            gap={20}
            direction="vertical"
            style={{
              flex: '0 0 100%',
            }}
          >
            <Heading level={2}>{productName}</Heading>

            {/* Price */}
            <Text variant="bodyLarge" weight="semibold">
              {currency} {price.toFixed(2)}
            </Text>

            {/* Rating */}
            <Stack gap={8} direction="horizontal" align="center">
              <div style={{ display: 'flex', gap: 'var(--ggui-spacing-1, 4px)', fontSize: '18px' }}>
                {renderStars(rating)}
              </div>
              <Text variant="body">
                {rating.toFixed(1)} ({reviewCount} reviews)
              </Text>
            </Stack>

            {/* Stock Badge */}
            {!isOutOfStock && (
              <Badge variant={isLowStock ? 'warning' : 'success'} size="md">
                {isLowStock ? 'Low Stock' : 'In Stock'} — {stock} available
              </Badge>
            )}
            {isOutOfStock && (
              <Badge variant="error" size="md">
                Out of Stock
              </Badge>
            )}
          </Stack>
        </Stack>

        <Divider orientation="horizontal" margin={16} />

        {/* Middle Section: Tabs */}
        <Stack gap={16} direction="vertical">
          <Tabs
            items={tabItems}
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            size="md"
          />
        </Stack>

        <Divider orientation="horizontal" margin={16} />

        {/* Bottom Section: Purchase Controls */}
        <Stack gap={24} direction="vertical">
          {/* Quantity Selector */}
          <Stack gap={16} direction="vertical">
            <Text variant="label">Quantity</Text>
            <Stack gap={12} direction="horizontal" align="center">
              <Button
                variant="ghost"
                size="md"
                onClick={handleDecrement}
                disabled={quantity <= 1 || isOutOfStock}
                aria-label="Decrease quantity"
              >
                −
              </Button>
              <Text variant="body" align="center" style={{ minWidth: '40px' }}>
                {quantity}
              </Text>
              <Button
                variant="ghost"
                size="md"
                onClick={handleIncrement}
                disabled={quantity >= stock || isOutOfStock}
                aria-label="Increase quantity"
              >
                +
              </Button>
            </Stack>
          </Stack>

          {/* Error Message */}
          {submitError && (
            <Box
              background="var(--ggui-color-error-50, #fef2f2)"
              padding={12}
              borderRadius={8}
              style={{ border: '1px solid var(--ggui-color-error-200, #fecaca)' }}
            >
              <Text variant="body" color="var(--ggui-color-error-700, #b91c1c)">
                {submitError}
              </Text>
            </Box>
          )}

          {/* Success Message */}
          {submitSuccess && (
            <Box
              background="var(--ggui-color-success-50, #f0fdf4)"
              padding={12}
              borderRadius={8}
              style={{ border: '1px solid var(--ggui-color-success-200, #bbf7d0)' }}
            >
              <Text variant="body" color="var(--ggui-color-success-700, #15803d)">
                Added to cart successfully!
              </Text>
            </Box>
          )}

          {/* Add to Cart Button */}
          <Button
            variant="primary"
            size="lg"
            fullWidth={true}
            onClick={handleAddToCart}
            disabled={isOutOfStock || isSubmitting}
            loading={isSubmitting}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Heading, Text, Input, Button, Divider, Box, Icon } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Initial messages to display on mount */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

interface MessageWithId {
  sender?: string;
  text?: string;
  timestamp?: string;
  id: string;
}

interface TypingState {
  [sender: string]: boolean;
}

export default function ChatInterface(props: Props) {
  const [messageList, setMessageList] = useState<MessageWithId[]>(
    props.messages.map((m, i) => ({ ...m, id: `msg-${i}` }))
  );
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<TypingState>({});
  const messageEndRef = useRef<HTMLDivElement>(null);

  // Handle stream events
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const detail = event.detail ?? {};
      const { type, data } = detail;

      if (type === 'message' && data) {
        const newMessage: MessageWithId = {
          sender: data.sender ?? 'Unknown',
          text: data.text ?? '',
          timestamp: data.timestamp,
          id: `msg-${Date.now()}-${Math.random()}`,
        };
        setMessageList((prev) => [...prev, newMessage]);
        // Auto-scroll to bottom
        setTimeout(() => {
          messageEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }, 0);
      } else if (type === 'typing' && data) {
        setTypingUsers((prev) => ({
          ...prev,
          [data.sender ?? 'Unknown']: data.active ?? false,
        }));
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleSendMessage = () => {
    if (inputValue.trim().length === 0) return;

    const timestamp = new Date().toISOString();
    const payload = { text: inputValue, timestamp };

    window.dispatchEvent(
      new CustomEvent('ggui:action', {
        detail: {
          action: 'sendMessage',
          payload,
        },
      })
    );

    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        hour12: true,
      });
    } catch {
      return '';
    }
  };

  // Group consecutive messages from same sender
  const groupedMessages = messageList.reduce(
    (acc: Array<{ sender?: string; messages: MessageWithId[] }>, msg) => {
      if (acc.length === 0 || acc[acc.length - 1].sender !== msg.sender) {
        acc.push({ sender: msg.sender, messages: [msg] });
      } else {
        acc[acc.length - 1].messages.push(msg);
      }
      return acc;
    },
    []
  );

  const activeTypingUsers = Object.entries(typingUsers)
    .filter(([, active]) => active)
    .map(([sender]) => sender);

  const typingText =
    activeTypingUsers.length > 0
      ? `${activeTypingUsers.join(' and ')} ${activeTypingUsers.length === 1 ? 'is' : 'are'} typing...`
      : '';

  return (
    <Card shadow="md" padding={0} radius="lg" border={true}>
      <Stack
        direction="vertical"
        gap={0}
        align="stretch"
        style={{
          height: '600px',
          display: 'flex',
          flexDirection: 'column',
        }}
      >
        {/* Header */}
        <Box padding={`var(--ggui-spacing-4, 16px)`}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading
              level={3}
              color="var(--ggui-color-onSurface, #18181b)"
              style={{ margin: 0 }}
            >
              {props.title}
            </Heading>
            {props.participantCount !== undefined && (
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
              </Text>
            )}
          </Stack>
        </Box>

        <Divider orientation="horizontal" margin={0} />

        {/* Message List Area */}
        <Box
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: `var(--ggui-spacing-4, 16px)`,
            display: 'flex',
            flexDirection: 'column',
            gap: `var(--ggui-spacing-2, 8px)`,
            minHeight: 0,
          }}
          role="region"
          aria-label="Chat message list"
          aria-live="polite"
        >
          {groupedMessages.map((group, groupIdx) => {
            const isCurrentUser = group.sender === props.currentUser;
            return (
              <div
                key={`group-${groupIdx}`}
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: isCurrentUser ? 'flex-end' : 'flex-start',
                  gap: `var(--ggui-spacing-1, 4px)`,
                  marginTop:
                    groupIdx > 0 ? `var(--ggui-spacing-4, 16px)` : undefined,
                }}
              >
                {/* Show sender name only for non-current user */}
                {!isCurrentUser && (
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurface, #18181b)"
                    style={{ marginBottom: `var(--ggui-spacing-1, 4px)` }}
                  >
                    {group.sender}
                  </Text>
                )}

                {/* Message bubbles */}
                {group.messages.map((msg) => (
                  <Box
                    key={msg.id}
                    padding={`var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)`}
                    background={
                      isCurrentUser
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                    }
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    style={{
                      maxWidth: '60%',
                      wordWrap: 'break-word',
                    }}
                  >
                    <Text
                      variant="body"
                      color={
                        isCurrentUser
                          ? 'var(--ggui-color-surface, #ffffff)'
                          : 'var(--ggui-color-onSurface, #18181b)'
                      }
                      style={{ margin: 0 }}
                    >
                      {msg.text}
                    </Text>
                    {msg.timestamp && (
                      <Text
                        variant="caption"
                        color={
                          isCurrentUser
                            ? 'var(--ggui-color-primary-100, #e0f2fe)'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                        }
                        style={{
                          marginTop: `var(--ggui-spacing-1, 4px)`,
                          fontSize: `var(--ggui-font-size-xs, 12px)`,
                        }}
                      >
                        {formatTime(msg.timestamp)}
                      </Text>
                    )}
                  </Box>
                ))}
              </div>
            );
          })}

          {/* Typing Indicator */}
          {typingText && (
            <div
              style={{
                display: 'flex',
                alignItems: 'flex-start',
                marginTop: `var(--ggui-spacing-4, 16px)`,
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                style={{
                  fontStyle: 'italic',
                  margin: 0,
                }}
                aria-live="polite"
                aria-label={typingText}
              >
                {typingText}
              </Text>
            </div>
          )}

          <div ref={messageEndRef} />
        </Box>

        <Divider orientation="horizontal" margin={0} />

        {/* Input Area */}
        <Box
          padding={`var(--ggui-spacing-4, 16px)`}
          style={{
            display: 'flex',
            gap: `var(--ggui-spacing-2, 8px)`,
            alignItems: 'flex-end',
          }}
        >
          <div style={{ flex: 1 }}>
            <Input
              label="Message"
              placeholder="Type a message..."
              value={inputValue}
              onChange={setInputValue}
              onKeyDown={handleKeyDown}
              aria-label="Message input"
            />
          </div>
          <Button
            variant="primary"
            size="md"
            onClick={handleSendMessage}
            disabled={inputValue.trim().length === 0}
            rightIcon={<Icon name="send" size={16} />}
            aria-label="Send message"
          >
            Send
          </Button>
        </Box>
      </Stack>
    </Card>
  );
}

