import React, { useState, useEffect } from 'react';
import { Container, Stack, Heading, Text, Card, Badge, Icon, Spinner } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
}

export default function StockTickerDashboard(props: Props) {
  const [displayedStocks, setDisplayedStocks] = useState<Stock[]>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toISOString());
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());
  const [connectionStatus, setConnectionStatus] = useState<'connecting' | 'connected' | 'disconnected'>('connecting');

  // Initialize from props
  useEffect(() => {
    setDisplayedStocks(props.stocks ?? []);
  }, [props.stocks]);

  // Listen for stream events
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;

      if (customEvent.detail?.type === 'priceUpdate') {
        const { symbol, price, change, changePercent } = customEvent.detail.data;

        setDisplayedStocks(prev =>
          prev.map(stock =>
            stock.symbol === symbol
              ? { ...stock, price, change, changePercent }
              : stock
          )
        );

        setLastUpdated(new Date().toISOString());

        // Trigger flash animation
        setFlashingSymbols(prev => new Set([...prev, symbol]));

        // Clear flash after 500ms
        setTimeout(() => {
          setFlashingSymbols(prev => {
            const next = new Set(prev);
            next.delete(symbol);
            return next;
          });
        }, 500);
      } else if (customEvent.detail?.type === 'marketStatus') {
        const { status, timestamp } = customEvent.detail.data;

        if (status === 'open') {
          setConnectionStatus('connected');
        } else if (status === 'closed') {
          setConnectionStatus('disconnected');
        } else {
          setConnectionStatus('connecting');
        }

        if (timestamp) {
          setLastUpdated(timestamp);
        }
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const getStatusBadgeVariant = () => {
    switch (connectionStatus) {
      case 'connected':
        return 'success';
      case 'disconnected':
        return 'error';
      default:
        return 'warning';
    }
  };

  const getStatusText = () => {
    switch (connectionStatus) {
      case 'connected':
        return 'Connected';
      case 'disconnected':
        return 'Market Closed';
      default:
        return 'Connecting...';
    }
  };

  const formatTimestamp = (isoString: string) => {
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch {
      return 'N/A';
    }
  };

  return (
    <Container maxWidth="lg" padding={`var(--ggui-spacing-6, 24px)`}>
      <Stack direction="vertical" gap={`var(--ggui-spacing-6, 24px)`}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center" gap={`var(--ggui-spacing-4, 16px)`}>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Heading>
          <Stack direction="horizontal" gap={`var(--ggui-spacing-4, 16px)`} align="center">
            <Badge variant={getStatusBadgeVariant()} size="md">
              {connectionStatus === 'connecting' && <Spinner size={12} color="currentColor" />}
              {getStatusText()}
            </Badge>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formatTimestamp(lastUpdated)}
            </Text>
          </Stack>
        </Stack>

        {/* Stock Grid */}
        {displayedStocks && displayedStocks.length > 0 ? (
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
              gap: `var(--ggui-spacing-4, 16px)`,
            } as React.CSSProperties}
          >
            {displayedStocks.map((stock) => {
              const isPositive = (stock.changePercent ?? 0) > 0;
              const isNegative = (stock.changePercent ?? 0) < 0;
              const isFlashing = flashingSymbols.has(stock.symbol ?? '');

              let borderColor = 'var(--ggui-color-outlineVariant, #e4e4e7)';
              if (isPositive) {
                borderColor = 'var(--ggui-color-success-200, #bbf7d0)';
              } else if (isNegative) {
                borderColor = 'var(--ggui-color-error-200, #fecaca)';
              }

              const cardStyle: React.CSSProperties = {
                border: `1px solid ${borderColor}`,
                animation: isFlashing ? 'ggui-scaleIn 500ms ease-out' : undefined,
              };

              return (
                <Card
                  key={stock.symbol ?? Math.random()}
                  shadow="md"
                  padding={16}
                  radius="lg"
                  border={false}
                >
                  <div style={cardStyle}>
                    <Stack direction="vertical" gap={8}>
                      {/* Ticker Symbol */}
                      <Text
                        variant="overline"
                        color="var(--ggui-color-primary-600, #0284c7)"
                      >
                        {stock.symbol ?? 'N/A'}
                      </Text>

                      {/* Company Name */}
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {stock.name ?? 'Unknown Company'}
                      </Text>

                      {/* Current Price */}
                      <Text
                        size="2xl"
                        weight="bold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        ${stock.price?.toFixed(2) ?? '0.00'}
                      </Text>

                      {/* Change Amount + Percentage + Arrow */}
                      <Stack
                        direction="horizontal"
                        gap={4}
                        align="center"
                      >
                        {/* Arrow Icon */}
                        <Icon
                          name={isPositive ? 'chevron-up' : isNegative ? 'chevron-down' : ''}
                          size={16}
                          color={
                            isPositive
                              ? 'var(--ggui-color-success-500, #22c55e)'
                              : isNegative
                              ? 'var(--ggui-color-error-500, #ef4444)'
                              : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                          }
                        />

                        {/* Change Text */}
                        <Text
                          variant="body"
                          color={
                            isPositive
                              ? 'var(--ggui-color-success-600, #16a34a)'
                              : isNegative
                              ? 'var(--ggui-color-error-600, #dc2626)'
                              : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                          }
                        >
                          ${stock.change?.toFixed(2) ?? '0.00'} ({stock.changePercent?.toFixed(2) ?? '0.00'}%)
                        </Text>
                      </Stack>
                    </Stack>
                  </div>
                </Card>
              );
            })}
          </div>
        ) : (
          <Card shadow="md" padding={32} radius="lg" border={true}>
            <Stack direction="vertical" gap={8} align="center" justify="center">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {connectionStatus === 'connecting'
                  ? 'Connecting to market feed...'
                  : 'No stock data available. Awaiting market data…'}
              </Text>
              {connectionStatus === 'connecting' && (
                <Spinner size={24} color="var(--ggui-color-primary-600, #0284c7)" />
              )}
            </Stack>
          </Card>
        )}
      </Stack>

      {/* Animation Styles */}
      <style>{`
        @keyframes ggui-scaleIn {
          from {
            opacity: 0;
            transform: scale(0.95);
          }
          to {
            opacity: 1;
            transform: scale(1);
          }
        }

        @keyframes ggui-spin {
          from {
            transform: rotate(0deg);
          }
          to {
            transform: rotate(360deg);
          }
        }
      `}</style>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Input,
  Select,
  Toggle,
  Button,
  Progress,
  Badge,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (profile: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

interface FormData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Errors {
  name?: string;
  email?: string;
}

export default function OnboardingWizard(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? '👤'),
    role: props.initialProfile?.role ?? (props.roleOptions[0] ?? ''),
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  const [errors, setErrors] = useState<Errors>({});

  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors: Errors = {};

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const isStep1Valid = (): boolean => {
    return (
      formData.name.trim().length > 0 &&
      formData.email.trim().length > 0 &&
      validateEmail(formData.email)
    );
  };

  const handleNameChange = (value: string) => {
    setFormData((prev) => ({ ...prev, name: value }));
  };

  const handleEmailChange = (value: string) => {
    setFormData((prev) => ({ ...prev, email: value }));
  };

  const handleAvatarSelect = (emoji: string) => {
    setFormData((prev) => ({ ...prev, avatar: emoji }));
  };

  const handleRoleChange = (value: string) => {
    setFormData((prev) => ({ ...prev, role: value }));
  };

  const handleEmailNotificationsChange = (checked: boolean) => {
    setFormData((prev) => ({ ...prev, emailNotifications: checked }));
  };

  const handleThemeChange = (checked: boolean) => {
    setFormData((prev) => ({ ...prev, theme: checked ? 'dark' : 'light' }));
  };

  const handleNext = () => {
    if (currentStep === 1) {
      if (!validateStep1()) return;
    }
    if (currentStep < 3) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleComplete = () => {
    if (props.onComplete) {
      props.onComplete(formData);
    }
  };

  const roleOptions = props.roleOptions.map((role) => ({
    value: role,
    label: role,
  }));

  return (
    <Container maxWidth="lg" center padding={24}>
      <Stack gap={16}>
        {/* Step Indicator */}
        <Stack gap={12}>
          <Stack direction="horizontal" gap={12} justify="start" align="center">
            <Progress value={currentStep} max={3} size="md" />
            <Stack
              direction="horizontal"
              gap={8}
              align="center"
              justify="start"
            >
              {[1, 2, 3].map((step) => (
                <Badge
                  key={step}
                  variant={currentStep >= step ? 'primary' : 'default'}
                  pill
                >
                  {step}
                </Badge>
              ))}
            </Stack>
          </Stack>
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            Step {currentStep} of 3
          </Text>
        </Stack>

        <Divider margin={16} />

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Step 1: Create Your Profile</Heading>

              <Input
                label="Name"
                required
                value={formData.name}
                onChange={handleNameChange}
                error={errors.name}
                placeholder="Enter your full name"
              />

              <Input
                label="Email"
                type="email"
                required
                value={formData.email}
                onChange={handleEmailChange}
                error={errors.email}
                placeholder="Enter your email address"
              />

              <Stack gap={8}>
                <Text variant="label">Choose an avatar:</Text>
                <Box paddingY={8}>
                  <Stack direction="horizontal" gap={8} align="center">
                    {props.avatarOptions.map((avatar) => (
                      <Button
                        key={avatar}
                        variant={
                          formData.avatar === avatar ? 'primary' : 'ghost'
                        }
                        onClick={() => handleAvatarSelect(avatar)}
                        aria-label={`Select ${avatar} avatar`}
                      >
                        {avatar}
                      </Button>
                    ))}
                  </Stack>
                </Box>
              </Stack>

              <Stack
                direction="horizontal"
                gap={12}
                justify="between"
                align="end"
              >
                <div />
                <Button
                  variant="primary"
                  onClick={handleNext}
                  disabled={!isStep1Valid()}
                >
                  Next
                </Button>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Step 2: Set Your Preferences</Heading>

              <Select
                label="Role"
                required
                value={formData.role}
                onChange={handleRoleChange}
                options={roleOptions}
              />

              <Toggle
                label="Email Notifications"
                checked={formData.emailNotifications}
                onChange={handleEmailNotificationsChange}
                size="md"
              />

              <Toggle
                label="Dark Theme"
                checked={formData.theme === 'dark'}
                onChange={handleThemeChange}
                size="md"
              />

              <Stack
                direction="horizontal"
                gap={12}
                justify="between"
                align="end"
              >
                <Button variant="ghost" onClick={handleBack}>
                  Back
                </Button>
                <Button variant="primary" onClick={handleNext}>
                  Next
                </Button>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Step 3: Review & Confirm</Heading>

              <Card shadow="sm" padding={16} radius="md">
                <Stack gap={12}>
                  <Stack gap={4}>
                    <Text variant="label">Name:</Text>
                    <Text variant="body">{formData.name}</Text>
                  </Stack>

                  <Stack gap={4}>
                    <Text variant="label">Email:</Text>
                    <Text variant="body">{formData.email}</Text>
                  </Stack>

                  <Stack gap={4}>
                    <Text variant="label">Avatar:</Text>
                    <Text variant="body">{formData.avatar}</Text>
                  </Stack>

                  <Stack gap={4}>
                    <Text variant="label">Role:</Text>
                    <Text variant="body">{formData.role}</Text>
                  </Stack>

                  <Stack gap={4}>
                    <Text variant="label">Email Notifications:</Text>
                    <Text variant="body">
                      {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                    </Text>
                  </Stack>

                  <Stack gap={4}>
                    <Text variant="label">Theme:</Text>
                    <Text variant="body">
                      {formData.theme === 'dark' ? 'Dark' : 'Light'}
                    </Text>
                  </Stack>
                </Stack>
              </Card>

              <Stack
                direction="horizontal"
                gap={12}
                justify="between"
                align="end"
              >
                <Button variant="ghost" onClick={handleBack}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete}>
                  Complete Setup
                </Button>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}
